from collections import deque, defaultdict

class Solution:
    def secondMinimum(self, n, edges, time, change):
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)
        dist1 = [-1] * (n + 1)
        dist2 = [-1] * (n + 1)
        dist1[1] = 0
        q = deque([(1, 0)])
        while q:
            u, d = q.popleft()
            for v in graph[u]:
                if dist1[v] == -1:
                    dist1[v] = d + 1
                    q.append((v, d + 1))
                elif dist2[v] == -1 and d + 1 != dist1[v]:
                    dist2[v] = d + 1
                    q.append((v, d + 1))
        moves = dist2[n]
        result = 0
        for _ in range(moves):
            if (result // change) % 2 == 1:
                result = (result // change + 1) * change
            result += time
        return result

