var secondMinimum = function(n, edges, time, change) {
    const graph = Array.from({length: n + 1}, () => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }
    const dist1 = new Array(n + 1).fill(-1);
    const dist2 = new Array(n + 1).fill(-1);
    dist1[1] = 0;
    const queue = [[1, 0]];
    let head = 0;
    while (head < queue.length) {
        const [u, d] = queue[head++];
        for (const v of graph[u]) {
            if (dist1[v] === -1) {
                dist1[v] = d + 1;
                queue.push([v, d + 1]);
            } else if (dist2[v] === -1 && d + 1 !== dist1[v]) {
                dist2[v] = d + 1;
                queue.push([v, d + 1]);
            }
        }
    }
    const moves = dist2[n];
    let result = 0;
    for (let i = 0; i < moves; i++) {
        if (Math.floor(result / change) % 2 === 1) {
            result = (Math.floor(result / change) + 1) * change;
        }
        result += time;
    }
    return result;
};
